.tablist { position: relative; display: inline-flex; padding: 4px; background: rgba(0,0,0,0.06); border-radius: 999px; }
.tab { position: relative; z-index: 1; border: 0; background: none; padding: 10px 18px; border-radius: 999px; cursor: pointer; transition: color 180ms ease; }
.tab[aria-selected="true"] { color: #0a0a0a; }
/* 인디케이터는 별도 엘리먼트 — transform·width만 보간 */
.pill { position: absolute; top: 4px; left: 0; height: calc(100% - 8px); border-radius: 999px; background: #fff;
        transition: transform 280ms cubic-bezier(0.4,0,0.2,1), width 280ms cubic-bezier(0.4,0,0.2,1); }

var tabs = [].slice.call(document.querySelectorAll(".tab"));
var pill = document.querySelector(".pill");
var current = 0;
function movePill(i){
  var t = tabs[i];                              // 측정: offsetLeft / offsetWidth
  pill.style.transform = "translateX(" + t.offsetLeft + "px)";
  pill.style.width = t.offsetWidth + "px";
}
function select(i){
  current = i;
  tabs.forEach(function(t, j){ t.setAttribute("aria-selected", j === i ? "true" : "false"); });
  movePill(i);
}
tabs.forEach(function(t, i){ t.addEventListener("click", function(){ select(i); }); });
// 키보드 ←→ 접근성 (role="tablist" 컨테이너에서)
document.querySelector(".tablist").addEventListener("keydown", function(e){
  var dir = e.key === "ArrowRight" ? 1 : (e.key === "ArrowLeft" ? -1 : 0);
  if (!dir) return;
  e.preventDefault();
  var n = (current + dir + tabs.length) % tabs.length;
  select(n); tabs[n].focus();
});
// 리사이즈·폰트 로드 후 재측정 필수
window.addEventListener("resize", function(){ movePill(current); });
if (document.fonts) document.fonts.ready.then(function(){ movePill(current); });
select(0);

.tablist { position: relative; display: inline-flex; gap: 4px; border-bottom: 1px solid rgba(0,0,0,0.12); }
.tab { border: 0; background: none; padding: 13px 14px; cursor: pointer; transition: color 180ms ease; }
.bar { position: absolute; bottom: -1px; left: 0; height: 2px; background: currentColor;
       transition: transform 260ms cubic-bezier(0.4,0,0.2,1), width 260ms cubic-bezier(0.4,0,0.2,1); }
/* 패널 페이드 교체 (re-trigger용 keyframe) */
.panel-in { animation: panel-in 220ms cubic-bezier(0.4,0,0.2,1) both; }
@keyframes panel-in { from { opacity: 0; transform: translateY(6px); } to { opacity: 1; transform: none; } }

var bar = document.querySelector(".bar");
function moveBar(i){
  var t = tabs[i];
  bar.style.transform = "translateX(" + t.offsetLeft + "px)";
  bar.style.width = t.offsetWidth + "px";
}
function swapPanel(i){
  panels.forEach(function(pn, j){ pn.hidden = j !== i; pn.classList.remove("panel-in"); });
  void panels[i].offsetWidth;          // reflow로 keyframe 재시작
  panels[i].classList.add("panel-in");
}
function select(i){
  tabs.forEach(function(t, j){ t.setAttribute("aria-selected", j === i ? "true" : "false"); });
  moveBar(i); swapPanel(i);
}
window.addEventListener("resize", function(){ moveBar(current); });

.panels { display: grid; }
.panel { grid-area: 1 / 1;                /* 같은 칸에 겹침 — 높이 점프 없음 */
  opacity: 0; transform: translateY(8px); pointer-events: none;
  transition: opacity 120ms ease, transform 120ms ease; }   /* out: 120ms */
.panel.is-active { opacity: 1; transform: none; pointer-events: auto;
  transition: opacity 200ms cubic-bezier(0.4,0,0.2,1), transform 200ms cubic-bezier(0.4,0,0.2,1); } /* in: 200ms */

var swapTimer = null;
function update(i, prev){
  movePill(i);                              // 인디케이터는 즉시(transition 없음)
  if (i === prev) return;
  panels.forEach(function(pn){ pn.classList.remove("is-active"); });   // 1) 전부 out (120ms)
  clearTimeout(swapTimer);
  swapTimer = setTimeout(function(){       // 2) 120ms 뒤 새 패널 in (200ms)
    panels.forEach(function(pn, j){ pn.classList.toggle("is-active", j === i); });
  }, 120);
}

/* 유령: 빠르고(120ms) 옅게 — hover 추적 전용 */
.ghost { position: absolute; border-radius: 999px; background: rgba(255,255,255,0.1); opacity: 0;
         transition: transform 120ms ease-out, width 120ms ease-out, opacity 140ms ease; }
.tablist.is-hovering .ghost { opacity: 1; }
/* 확정 필: 느리고(280ms) 진하게 — 선택 상태 전용 */
.pill { position: absolute; border-radius: 999px; background: #fff;
        transition: transform 280ms cubic-bezier(0.4,0,0.2,1), width 280ms cubic-bezier(0.4,0,0.2,1); }

function place(el, t){
  el.style.transform = "translateX(" + t.offsetLeft + "px)";
  el.style.width = t.offsetWidth + "px";
}
tabs.forEach(function(t, i){
  t.addEventListener("mouseenter", function(){       // hover → 유령이 따라옴
    place(ghost, t);
    list.classList.add("is-hovering");
  });
  t.addEventListener("click", function(){ select(i); });   // click → 확정 필 정착
});
list.addEventListener("mouseleave", function(){ list.classList.remove("is-hovering"); });

.layout { display: flex; gap: 32px; align-items: flex-start; }
.tablist { position: relative; display: flex; flex-direction: column; gap: 2px; padding-left: 15px; }
.tab { text-align: left; border: 0; background: none; padding: 11px 16px; border-radius: 10px; cursor: pointer; }
.tab[aria-selected="true"] { background: rgba(0,0,0,0.05); }
.rail { position: absolute; left: 0; top: 0; width: 3px; border-radius: 2px; background: #6366f1;
        transition: transform 280ms cubic-bezier(0.4,0,0.2,1), height 280ms cubic-bezier(0.4,0,0.2,1); }

var rail = document.querySelector(".rail");
function moveRail(i){
  var t = tabs[i];                          // 세로축 측정: offsetTop / offsetHeight
  rail.style.transform = "translateY(" + t.offsetTop + "px)";
  rail.style.height = t.offsetHeight + "px";
}
// 세로 tablist는 ↑↓ 키로 이동 (aria-orientation="vertical")
list.addEventListener("keydown", function(e){
  var dir = e.key === "ArrowDown" ? 1 : (e.key === "ArrowUp" ? -1 : 0);
  if (!dir) return;
  e.preventDefault();
  var n = (current + dir + tabs.length) % tabs.length;
  select(n); tabs[n].focus();
});

.tab { display: inline-flex; align-items: center; gap: 8px; }
.badge { display: inline-flex; align-items: center; justify-content: center;
  min-width: 20px; height: 20px; padding: 0 6px; border-radius: 999px;
  background: rgba(0,0,0,0.08); font-size: 11px; font-weight: 700;
  transition: background 180ms ease, color 180ms ease; }
/* 활성 순간 반전 + pop — 셀렉터가 새로 매칭되며 keyframe이 자동 재생 */
.tab[aria-selected="true"] .badge { background: #111; color: #fff;
  animation: badge-pop 260ms cubic-bezier(0.34,1.56,0.64,1); }
@keyframes badge-pop { 0% { transform: scale(1.3); } 100% { transform: scale(1); } }

// 뱃지 pop은 CSS만으로 동작 — aria-selected가 바뀌면
// [aria-selected="true"] .badge 셀렉터가 새로 매칭되며 keyframe이 재시작된다.
function select(i){
  tabs.forEach(function(t, j){ t.setAttribute("aria-selected", j === i ? "true" : "false"); });
  movePill(i); swapPanel(i);
}
// 카운트가 실시간으로 바뀌는 경우: 숫자 교체 후 강제 pop 재생
function setCount(i, n){
  var b = tabs[i].querySelector(".badge");
  b.textContent = n;
  b.style.animation = "none"; void b.offsetWidth; b.style.animation = "";
}

.tab { display: flex; flex-direction: column; align-items: center; gap: 6px;
  border: 0; background: none; padding: 10px 20px; border-radius: 12px; font-size: 12px; cursor: pointer; }
.ico { color: rgba(0,0,0,0.4); transition: color 200ms ease; }
.tab[aria-selected="true"] { background: rgba(0,0,0,0.05); }
/* 오버슈트 스프링: 0.6 → 1.12 → 1 */
.tab[aria-selected="true"] .ico { color: #6366f1;
  animation: ico-pop 320ms cubic-bezier(0.34,1.56,0.64,1); }
@keyframes ico-pop { 0% { transform: scale(0.6); } 60% { transform: scale(1.12); } 100% { transform: scale(1); } }

// 아이콘 pop은 CSS only — aria-selected 토글만 하면 keyframe이 재시작된다.
tabs.forEach(function(t, i){
  t.addEventListener("click", function(){
    tabs.forEach(function(x, j){ x.setAttribute("aria-selected", j === i ? "true" : "false"); });
    panels.forEach(function(pn, j){ pn.hidden = j !== i; });
  });
});
// prefers-reduced-motion이면 스프링 제거
// @media (prefers-reduced-motion: reduce) { .ico { animation: none !important; } }

/* 핵심: transform과 width를 같은 duration·같은 이징으로 묶는다 */
.pill { position: absolute; top: 4px; left: 0; height: calc(100% - 8px);
  border-radius: 999px; background: #fff; will-change: transform, width;
  transition: transform 300ms cubic-bezier(0.4,0,0.2,1),
              width     300ms cubic-bezier(0.4,0,0.2,1); }

function movePill(i){
  var t = tabs[i];
  // 좌표와 폭을 한 프레임에 함께 적용 — 따로 적용하면 모핑이 어긋난다
  pill.style.transform = "translateX(" + t.offsetLeft + "px)";
  pill.style.width = t.offsetWidth + "px";
}
// 라벨이 동적으로 바뀌는 경우(i18n·데이터 라벨)에도 재측정만 하면 끝
window.addEventListener("resize", function(){ movePill(current); });
if (document.fonts) document.fonts.ready.then(function(){ movePill(current); });

.panels { overflow: hidden; }                /* 뷰포트 — 마스크 역할 */
.track { display: flex; will-change: transform;
  transition: transform 360ms cubic-bezier(0.4,0,0.2,1); }
/* flex-basis 100% + shrink 0 — 트랙 폭은 컨테이너와 같고 패널이 옆으로 넘친다.
   그래서 translateX(-i*100%)가 정확히 패널 i 위치가 된다 */
.panel { flex: 0 0 100%; min-width: 0; }
.panel[aria-hidden="true"] { opacity: 0.25; transition: opacity 360ms ease; }

var track = document.querySelector(".track");
function update(i, prev){
  movePill(i);                              // 인디케이터는 표준 측정 이동
  // 새 인덱스가 크면 우→좌, 작으면 좌→우 — 방향은 translateX 보간이 자동 결정
  track.style.transform = "translateX(" + (-i * 100) + "%)";
  // 화면 밖 패널은 보조기기·포커스 대상에서 제외
  panels.forEach(function(pn, j){
    pn.setAttribute("aria-hidden", j === i ? "false" : "true");
  });
}

.tab { display: flex; flex-direction: column; gap: 9px; min-width: 84px;
  border: 0; background: none; padding: 8px 2px 10px; cursor: pointer; text-align: left; }
/* 진행 바: 트랙 + fill — fill 폭은 JS가 rAF로 매 프레임 갱신 */
.prog { display: block; height: 3px; border-radius: 2px;
  background: rgba(0,0,0,0.12); overflow: hidden; }
.prog > span { display: block; width: 0%; height: 100%; background: #111; }

var DUR = 5000;                                  // 탭당 5초
var fills = [].slice.call(document.querySelectorAll(".prog > span"));
var raf = null, startTs = null, elapsed = 0, paused = false;
function frame(ts){
  if (startTs === null || paused) startTs = ts - elapsed;   // 일시정지: 기준점을 미뤄 진행 동결
  else elapsed = ts - startTs;
  var ratio = Math.min(1, elapsed / DUR);
  fills[current].style.width = (ratio * 100) + "%";
  if (ratio >= 1) { select((current + 1) % tabs.length); return; }   // 자동 다음 탭 (순환)
  raf = requestAnimationFrame(frame);
}
function update(i){
  fills.forEach(function(f, j){ f.style.width = j < i ? "100%" : "0%"; });  // 지난 탭은 가득
  cancelAnimationFrame(raf);
  startTs = null; elapsed = 0;                   // 클릭 점프 포함 — 항상 0부터 재시작
  raf = requestAnimationFrame(frame);
}
// 사용자 개입이 항상 이긴다: hover 일시정지 / 이탈 시 재개
list.addEventListener("mouseenter", function(){ paused = true; });
list.addEventListener("mouseleave", function(){ paused = false; });
